// Claim: the permission system denies access when a user's role lacks the required permission flag.

import { check } from "../../src/auth/permissions";
import { Role, hasPermission } from "../../src/models/role";

describe("Permission System Denial", () => {
  describe("check() function", () => {
    it("denies access when role lacks the required permission flag", () => {
      // Create a role with some permissions but NOT the 'read:admin' permission
      const limitedRole: Role = {
        name: "limited-user",
        permissionFlags: ["read:users", "write:users", "read:reports"],
      };

      // Attempt to check access for 'read:admin' permission
      // The system should deny because 'read:admin' is not in permissionFlags
      const result = check(limitedRole, "read:admin");

      // Oracle honesty: this test would fail if the claim were false because
      // the implementation would incorrectly return true (access granted)
      // when the role actually lacks the 'read:admin' permission flag.
      // A correct implementation must return false when the flag is absent.
      expect(result).toBe(false);
    });

    it("denies access when role has empty permission flags", () => {
      const noPermissionsRole: Role = {
        name: "no-permissions",
        permissionFlags: [],
      };

      const result = check(noPermissionsRole, "read:users");

      expect(result).toBe(false);
    });

    it("denies access when required permission is not in role's flag set", () => {
      const customRole: Role = {
        name: "custom-role",
        permissionFlags: ["write:content", "delete:content"],
      };

      // Role has write and delete but not read
      const result = check(customRole, "read:content");

      expect(result).toBe(false);
    });
  });

  describe("hasPermission() resolution", () => {
    it("returns false when role lacks the requested permission", () => {
      const viewerRole: Role = {
        name: "viewer",
        permissionFlags: ["read:public"],
      };

      // Oracle honesty: this test would fail if hasPermission incorrectly
      // returns true for a role that doesn't have the permission flag.
      const result = hasPermission(viewerRole, "write:public");

      expect(result).toBe(false);
    });

    it("correctly identifies missing permission among multiple flags", () => {
      const mixedRole: Role = {
        name: "mixed-role",
        permissionFlags: ["read:users", "read:reports", "write:users"],
      };

      // Role has read:users and read:reports but NOT read:admin
      const result = hasPermission(mixedRole, "read:admin");

      expect(result).toBe(false);
    });
  });
});
